mapper.select:
SELECT o.id AS order_id, o.slot_id, o.start_time, o.end_time, o.total_amount, o.status, o.create_time, o.pay_time, o.cancel_time, o.actual_end_time, o.actual_amount, p.address FROM `order` o LEFT JOIN parking_slot p ON o.slot_id = p.id WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
